/**
 * Tests for AudioMixer
 *
 * Tests pure logic (filter building) and mocks exec/fs for I/O methods.
 */

import { AudioMixer, getAudioMixer } from '@/lib/audio/audio-mixer';

// Mock child_process, fs, and path
jest.mock('child_process', () => ({
  exec: jest.fn(),
}));
jest.mock('util', () => ({
  promisify: (fn: unknown) => fn,
}));
jest.mock('fs', () => ({
  existsSync: jest.fn(),
}));
jest.mock('path', () => ({
  join: (...parts: string[]) => parts.join('/'),
}));

import { exec } from 'child_process';
import { existsSync } from 'fs';

const mockedExec = exec as unknown as jest.Mock;
const mockedExistsSync = existsSync as unknown as jest.Mock;

describe('AudioMixer', () => {
  let mixer: AudioMixer;

  beforeEach(() => {
    mixer = new AudioMixer();
    jest.clearAllMocks();
  });

  // =========================================================================
  // mixVideoWithMusic
  // =========================================================================

  describe('mixVideoWithMusic', () => {
    it('returns error when video file does not exist', async () => {
      mockedExistsSync.mockReturnValue(false);

      const result = await mixer.mixVideoWithMusic({
        videoPath: '/tmp/video.mp4',
        musicPath: '/tmp/music.mp3',
        outputPath: '/tmp/output.mp4',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('não encontrado');
    });

    it('builds FFmpeg command with ducking when enabled', async () => {
      // First call: video exists, second: music exists, third: output exists
      mockedExistsSync
        .mockReturnValueOnce(true) // videoPath exists
        .mockReturnValueOnce(true) // musicPath exists
        .mockReturnValueOnce(true); // outputPath exists after render

      // First exec: ffprobe (duration), second exec: ffmpeg, third exec: ffprobe (output duration)
      mockedExec
        .mockResolvedValueOnce({ stdout: '120.5\n' }) // video duration
        .mockResolvedValueOnce({ stdout: '' })          // ffmpeg render
        .mockResolvedValueOnce({ stdout: '120.5\n' }); // output duration

      const result = await mixer.mixVideoWithMusic({
        videoPath: '/tmp/video.mp4',
        musicPath: '/tmp/music.mp3',
        outputPath: '/tmp/output.mp4',
        musicVolume: 0.3,
        duckingEnabled: true,
      });

      expect(result.success).toBe(true);
      expect(result.outputPath).toBe('/tmp/output.mp4');
      expect(result.duration).toBe(120.5);

      // Verify FFmpeg was called with ducking filter
      const ffmpegCall = mockedExec.mock.calls[1][0] as string;
      expect(ffmpegCall).toContain('sidechaincompress');
      expect(ffmpegCall).toContain('volume=0.3');
    });

    it('builds FFmpeg command without ducking when disabled', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)
        .mockReturnValueOnce(true)
        .mockReturnValueOnce(true);

      mockedExec
        .mockResolvedValueOnce({ stdout: '60\n' })
        .mockResolvedValueOnce({ stdout: '' })
        .mockResolvedValueOnce({ stdout: '60\n' });

      const result = await mixer.mixVideoWithMusic({
        videoPath: '/tmp/video.mp4',
        musicPath: '/tmp/music.mp3',
        outputPath: '/tmp/output.mp4',
        duckingEnabled: false,
      });

      expect(result.success).toBe(true);

      const ffmpegCall = mockedExec.mock.calls[1][0] as string;
      expect(ffmpegCall).not.toContain('sidechaincompress');
      expect(ffmpegCall).toContain('amix');
    });

    it('returns error when output is not generated', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)   // videoPath
        .mockReturnValueOnce(true)   // musicPath
        .mockReturnValueOnce(false); // outputPath NOT generated

      mockedExec
        .mockResolvedValueOnce({ stdout: '30\n' })
        .mockResolvedValueOnce({ stdout: '' });

      const result = await mixer.mixVideoWithMusic({
        videoPath: '/tmp/video.mp4',
        musicPath: '/tmp/music.mp3',
        outputPath: '/tmp/output.mp4',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('não foi gerado');
    });
  });

  // =========================================================================
  // normalizeVolume
  // =========================================================================

  describe('normalizeVolume', () => {
    it('normalizes audio with loudnorm filter', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)   // inputPath exists
        .mockReturnValueOnce(true);  // outputPath exists

      mockedExec.mockResolvedValueOnce({ stdout: '' });

      const result = await mixer.normalizeVolume({
        inputPath: '/tmp/input.mp3',
        outputPath: '/tmp/output.mp3',
        targetLoudness: -16,
        targetPeak: -1.5,
      });

      expect(result.success).toBe(true);
      expect(result.outputPath).toBe('/tmp/output.mp3');

      const cmd = mockedExec.mock.calls[0][0] as string;
      expect(cmd).toContain('loudnorm=I=-16:TP=-1.5:LRA=11');
    });

    it('returns error when input file does not exist', async () => {
      mockedExistsSync.mockReturnValue(false);

      const result = await mixer.normalizeVolume({
        inputPath: '/tmp/missing.mp3',
        outputPath: '/tmp/output.mp3',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('não encontrado');
    });

    it('returns error when output is not generated', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)   // input exists
        .mockReturnValueOnce(false); // output NOT generated

      mockedExec.mockResolvedValueOnce({ stdout: '' });

      const result = await mixer.normalizeVolume({
        inputPath: '/tmp/input.mp3',
        outputPath: '/tmp/output.mp3',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('não foi gerado');
    });
  });

  // =========================================================================
  // fadeInOut
  // =========================================================================

  describe('fadeInOut', () => {
    it('applies fade in and out', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)  // input
        .mockReturnValueOnce(true); // output

      mockedExec
        .mockResolvedValueOnce({ stdout: '60\n' })  // duration probe
        .mockResolvedValueOnce({ stdout: '' });       // ffmpeg

      const result = await mixer.fadeInOut({
        inputPath: '/tmp/audio.mp3',
        outputPath: '/tmp/faded.mp3',
        fadeIn: 2,
        fadeOut: 3,
      });

      expect(result.success).toBe(true);

      const cmd = mockedExec.mock.calls[1][0] as string;
      expect(cmd).toContain('afade=t=in:st=0:d=2');
      expect(cmd).toContain('afade=t=out:st=57:d=3');
    });

    it('skips fade when both are 0', async () => {
      mockedExistsSync.mockReturnValue(true);
      mockedExec
        .mockResolvedValueOnce({ stdout: '30\n' })
        .mockResolvedValueOnce({ stdout: '' }); // cp command

      const result = await mixer.fadeInOut({
        inputPath: '/tmp/audio.mp3',
        outputPath: '/tmp/copy.mp3',
        fadeIn: 0,
        fadeOut: 0,
      });

      expect(result.success).toBe(true);
    });

    it('returns error when input does not exist', async () => {
      mockedExistsSync.mockReturnValue(false);

      const result = await mixer.fadeInOut({
        inputPath: '/tmp/missing.mp3',
        outputPath: '/tmp/out.mp3',
        fadeIn: 1,
      });

      expect(result.success).toBe(false);
    });

    it('uses provided duration instead of probing', async () => {
      mockedExistsSync
        .mockReturnValueOnce(true)
        .mockReturnValueOnce(true);

      mockedExec.mockResolvedValueOnce({ stdout: '' }); // ffmpeg only, no probe

      const result = await mixer.fadeInOut({
        inputPath: '/tmp/audio.mp3',
        outputPath: '/tmp/faded.mp3',
        fadeIn: 1,
        fadeOut: 2,
        duration: 45,
      });

      expect(result.success).toBe(true);
      const cmd = mockedExec.mock.calls[0][0] as string;
      expect(cmd).toContain('afade=t=out:st=43:d=2');
    });
  });

  // =========================================================================
  // mixAudioFiles
  // =========================================================================

  describe('mixAudioFiles', () => {
    it('mixes multiple audio files', async () => {
      mockedExistsSync.mockReturnValue(true);
      mockedExec.mockResolvedValueOnce({ stdout: '' });

      const result = await mixer.mixAudioFiles({
        inputPaths: ['/tmp/a.mp3', '/tmp/b.mp3'],
        outputPath: '/tmp/mixed.mp3',
        volumes: [1.0, 0.5],
      });

      expect(result.success).toBe(true);

      const cmd = mockedExec.mock.calls[0][0] as string;
      expect(cmd).toContain('amix=inputs=2');
      expect(cmd).toContain('volume=1');
      expect(cmd).toContain('volume=0.5');
    });

    it('returns error for empty input array', async () => {
      const result = await mixer.mixAudioFiles({
        inputPaths: [],
        outputPath: '/tmp/mixed.mp3',
      });

      expect(result.success).toBe(false);
      expect(result.error).toContain('Nenhum arquivo');
    });

    it('uses default volumes (1.0) when not specified', async () => {
      mockedExistsSync.mockReturnValue(true);
      mockedExec.mockResolvedValueOnce({ stdout: '' });

      await mixer.mixAudioFiles({
        inputPaths: ['/tmp/a.mp3', '/tmp/b.mp3', '/tmp/c.mp3'],
        outputPath: '/tmp/mixed.mp3',
      });

      const cmd = mockedExec.mock.calls[0][0] as string;
      expect(cmd).toContain('amix=inputs=3');
    });
  });

  // =========================================================================
  // detectVoicePresence
  // =========================================================================

  describe('detectVoicePresence', () => {
    it('returns true when voice detected', async () => {
      mockedExec.mockResolvedValueOnce({
        stdout: 'silence_end: 1.5\n',
      });

      const result = await mixer.detectVoicePresence('/tmp/audio.mp3');
      expect(result).toBe(true);
    });

    it('returns true on detection failure (safe default)', async () => {
      mockedExec.mockRejectedValueOnce(new Error('ffmpeg not found'));

      const result = await mixer.detectVoicePresence('/tmp/audio.mp3');
      expect(result).toBe(true);
    });
  });

  // =========================================================================
  // Singleton
  // =========================================================================

  describe('getAudioMixer singleton', () => {
    it('returns same instance', () => {
      const a = getAudioMixer();
      const b = getAudioMixer();
      expect(a).toBe(b);
    });
  });
});
